                    } else if current_idx_a_plus_b < n1a + n0a + n1b {
                        '1'
                    } else {
                        '0'
                    };

                    let char_ba = if current_idx_b_plus_a < n1b {
                        '1'
                    } else if current_idx_b_plus_a < n1b + n0b {
                        '0'
                    } else if current_idx_b_plus_a < n1b + n0b + n1a {
                        '1'
                    } else {
                        '0'
                    };

                    if char_ab > char_ba {
                        return std::cmp::Ordering::Greater; // A+B is larger
                    }
                    if char_ab < char_ba {
                        return std::cmp::Ordering::Less;    // B+A is larger
                    }

                    current_idx_a_plus_b += 1;
                    current_idx_b_plus_a += 1;

                    // If both strings are exhausted, they are equal in value (which shouldn't happen if lengths differ, but safe guard)
                    if current_idx_a_plus_b >= n1a + n0a + n1b && current_idx_b_plus_a >= n1b + n0b + n1a {
                        break;
                    }
                }
                std::cmp::Ordering::Equal
            };

            // We want A to come before B if A+B > B+A, so we return Greater if A should come first.
            compare_concat(n1a, n0a, n1b, n0b).cmp(&std::cmp::Ordering::Equal)
        });


    // 3. Calculate the final value modulo M
    let mut result: i64 = 0;
    let mut current_power_of_2: i64 = 1; // This will track 2^k mod M, where k is the position from the right (0-indexed)

    // Iterate through the sorted segments in reverse order (from the least significant part to the most significant part)
    for &(n1, n0) in sorted_segments.iter().rev() {
        let length = n1 + n0;

        // The segment S_i has value V_i = (2^n1 - 1) * 2^n0.
        // Since we are calculating the total value by iterating from right to left (least significant to most significant),
        // we need to calculate the contribution of this segment shifted by the total length of segments already processed (which are to the right of it).

        // The contribution of S_i to the total value, when placed at the rightmost available spot, is V_i * 2^(total length of segments to its right).

        // Let's recalculate from left to right, accumulating the value.
    }

    // Recalculate from left to right
    result = 0;
    let mut total_length_so_far: i64 = 0;

    for &(n1, n0) in sorted_segments.iter() {
        let length = n1 + n0;

        // The value of the segment S_i = (2^n1 - 1) * 2^n0.

        // Value of S_i = (2^n1 - 1) * 2^n0 mod M
        // Since M is prime, we can use Fermat's Little Theorem for modular exponentiation if needed, but since n1, n0 <= 10^4, we can use standard modular exponentiation.

        let mod_pow = |base: i64, exp: i64, modulus: i64| -> i64 {
            let mut res = 1;
            let mut base = base % modulus;
            let mut exp = exp;
            while exp > 0 {
                if exp % 2 == 1 {
                    res = (res * base) % modulus;
                }
                base = (base * base) % modulus;
                exp /= 2;
            }
            res
        };

        // 2^n1 mod M
        let two_pow_n1 = mod_pow(2, n1, m);
        // (2^n1 - 1) mod M
        let val_ones = (two_pow_n1 - 1 + m) % m;
        // 2^n0 mod M
        let two_pow_n0 = mod_pow(2, n0, m);

        // V_i mod M = ((2^n1 - 1) mod M * 2^n0 mod M) mod M
        let segment_value = (val_ones * two_pow_n0) % m;

        // This segment is placed after total_length_so_far bits have been placed.
        // Its contribution to the total is segment_value * 2^(Total Length - segment_length). NO, this is wrong.

        // Total value V = V_1 * 2^(L_2 + ... + L_n) + V_2 * 2^(L_3 + ... + L_n) + ... + V_n
        // Where L_i = n1_i + n0_i.

        // If we process left-to-right (i=1 to n):
        // V = (V_1 * 2^(L_2 + ... + L_n) + ... + V_{n-1} * 2^L_n) + V_n

        // It's easier to calculate the value by shifting the existing result.
        // New Result = (Old Result * 2^L_i) + V_i

        // 2^L_i mod M
        let two_pow_length = mod_pow(2, length, m);

        // result = (result * 2^L_i) mod M
        result = (result * two_pow_length) % m;

        // result = (result + V_i) mod M
        result = (result + segment_value) % m;
    }

    result
}
